DROP FUNCTION IF EXISTS messages_get_by_message_ids_sp(text);
DROP FUNCTION IF EXISTS get_messages_by_session_idsp_count_sp(integer,text);
DROP FUNCTION IF EXISTS get_messages_by_session_idsp_paging_sp(integer,text,text,boolean,integer,integer);
DROP FUNCTION IF EXISTS get_messages_since_by_session_idand_message_key_sp(integer,text,integer);
DROP FUNCTION IF EXISTS get_messages_before_by_session_idand_message_key_sp(integer,text,integer);
DROP FUNCTION IF EXISTS messages_get_by_session_idturn_key_sp(integer,text);
CREATE TABLE IF NOT EXISTS messages (
	message_id integer GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
	session_id integer NOT NULL REFERENCES sessions(session_id) ON DELETE CASCADE,
	sequence_number integer NOT NULL,
	role text NOT NULL,
	content text NOT NULL,
	tool_name text NULL,
	tool_arguments text NULL,
	call_id text NULL,
	date_created timestamp NOT NULL DEFAULT now(),
	last_updated timestamp NOT NULL DEFAULT now(),
	data text NULL,
	is_compacted boolean NOT NULL DEFAULT false,
	compaction_epoch integer NULL,
	message_key text NOT NULL,
	turn_id text NOT NULL,
	compaction_epoch_key text NULL
);
DROP INDEX IF EXISTS ux_messages_message_key;
CREATE INDEX IF NOT EXISTS ix_messages_message_key ON messages(message_key);
CREATE INDEX IF NOT EXISTS ix_messages_session_id_message_id ON messages(session_id, message_id);
CREATE INDEX IF NOT EXISTS ix_messages_session_id_message_key ON messages(session_id, message_key);
CREATE INDEX IF NOT EXISTS ix_messages_session_id_sequence_number ON messages(session_id, sequence_number, message_id);
CREATE INDEX IF NOT EXISTS ix_messages_turn_id ON messages(turn_id);
CREATE INDEX IF NOT EXISTS ix_messages_compaction_epoch_key ON messages(compaction_epoch_key);

CREATE OR REPLACE FUNCTION get_message_rows()
RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text)
LANGUAGE sql AS $$
	SELECT message_id,session_id,sequence_number,role,content,tool_name,tool_arguments,call_id,date_created,last_updated,data,is_compacted,compaction_epoch,message_key,turn_id,compaction_epoch_key
	FROM messages;
$$;

CREATE OR REPLACE FUNCTION insert_message_sp(p_session_id integer,p_sequence_number integer,p_role text,p_content text,p_tool_name text,p_tool_arguments text,p_call_id text,p_data text,p_is_compacted boolean,p_compaction_epoch integer,p_message_key text,p_turn_id text,p_compaction_epoch_key text)
RETURNS TABLE ("MessageID" integer) LANGUAGE sql AS $$
	INSERT INTO messages(session_id,sequence_number,role,content,tool_name,tool_arguments,call_id,date_created,last_updated,data,is_compacted,compaction_epoch,message_key,turn_id,compaction_epoch_key)
	VALUES(p_session_id,p_sequence_number,p_role,p_content,p_tool_name,p_tool_arguments,p_call_id,now(),now(),p_data,p_is_compacted,p_compaction_epoch,p_message_key,p_turn_id,p_compaction_epoch_key)
	RETURNING message_id;
$$;

CREATE OR REPLACE FUNCTION update_message_sp(p_message_id integer,p_session_id integer,p_sequence_number integer,p_role text,p_content text,p_tool_name text,p_tool_arguments text,p_call_id text,p_data text,p_is_compacted boolean,p_compaction_epoch integer,p_message_key text,p_thread_key text,p_compaction_epoch_key text)
RETURNS void LANGUAGE sql AS $$
	UPDATE messages SET session_id=p_session_id,sequence_number=p_sequence_number,role=p_role,content=p_content,tool_name=p_tool_name,tool_arguments=p_tool_arguments,call_id=p_call_id,last_updated=now(),data=p_data,is_compacted=p_is_compacted,compaction_epoch=p_compaction_epoch,message_key=p_message_key,turn_id=p_thread_key,compaction_epoch_key=p_compaction_epoch_key
	WHERE message_id=p_message_id;
$$;
CREATE OR REPLACE FUNCTION remove_message_sp(p_message_id integer) RETURNS void LANGUAGE sql AS $$ DELETE FROM messages WHERE message_id=p_message_id; $$;
CREATE OR REPLACE FUNCTION copy_message_sp(p_message_id integer) RETURNS TABLE ("MessageID" integer) LANGUAGE sql AS $$
	INSERT INTO messages(session_id,sequence_number,role,content,tool_name,tool_arguments,call_id,date_created,last_updated,data,is_compacted,compaction_epoch,message_key,turn_id,compaction_epoch_key)
	SELECT session_id,sequence_number,role,content,tool_name,tool_arguments,call_id,now(),now(),data,is_compacted,compaction_epoch,message_key || '-copy-' || replace(clock_timestamp()::text, ' ', '-') || '-' || floor(random() * 1000000)::integer::text,turn_id,compaction_epoch_key FROM messages WHERE message_id=p_message_id
	RETURNING message_id;
$$;
CREATE OR REPLACE FUNCTION update_message_tool_arguments_sp(p_message_id integer,p_tool_arguments text) RETURNS void LANGUAGE sql AS $$ UPDATE messages SET tool_arguments=p_tool_arguments,last_updated=now() WHERE message_id=p_message_id; $$;
CREATE OR REPLACE FUNCTION update_message_data_sp(p_message_id integer,p_data text) RETURNS void LANGUAGE sql AS $$ UPDATE messages SET data=p_data,last_updated=now() WHERE message_id=p_message_id; $$;
CREATE OR REPLACE FUNCTION mark_message_as_compacted_sp(p_message_id integer) RETURNS void LANGUAGE sql AS $$ UPDATE messages SET is_compacted=true,last_updated=now() WHERE message_id=p_message_id; $$;
CREATE OR REPLACE FUNCTION mark_message_as_not_compacted_sp(p_message_id integer) RETURNS void LANGUAGE sql AS $$ UPDATE messages SET is_compacted=false,last_updated=now() WHERE message_id=p_message_id; $$;

CREATE OR REPLACE FUNCTION get_message_sp(p_message_id integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "MessageID"=p_message_id; $$;
CREATE OR REPLACE FUNCTION get_messages_sp() RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() ORDER BY "MessageID" ASC; $$;
