CREATE OR REPLACE FUNCTION messages_get_by_message_search_sp(p_search text,p_max_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "Role"='user' AND "Content" ILIKE '%'||COALESCE(p_search,'')||'%' ORDER BY "MessageID" DESC LIMIT p_max_rows; $$;
CREATE OR REPLACE FUNCTION messages_get_by_final_assistant_search_sp(p_search text,p_max_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "Role"='assistant' AND "Content" ILIKE '%'||COALESCE(p_search,'')||'%' ORDER BY "MessageID" DESC LIMIT p_max_rows; $$;
CREATE OR REPLACE FUNCTION get_messages_since_by_session_idand_message_key_sp(p_session_id integer,p_message_key text,p_num_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "SessionID"=p_session_id AND "MessageID" > (SELECT message_id FROM messages WHERE session_id=p_session_id AND message_key=p_message_key LIMIT 1) ORDER BY "MessageID" ASC LIMIT p_num_rows; $$;

CREATE OR REPLACE FUNCTION messages_get_turn_deltas_since_by_session_idand_message_key_sp(p_session_id integer,p_message_key text,p_num_rows integer) RETURNS TABLE ("MessageKey" text,"TurnID" text) LANGUAGE sql AS $$ SELECT message_key, COALESCE(turn_id, '') FROM messages WHERE session_id=p_session_id AND message_id > (SELECT message_id FROM messages WHERE session_id=p_session_id AND message_key=p_message_key LIMIT 1) ORDER BY message_id ASC LIMIT p_num_rows; $$;
CREATE OR REPLACE FUNCTION get_messages_before_by_session_idand_message_key_sp(p_session_id integer,p_message_key text,p_num_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM (SELECT * FROM get_message_rows() WHERE "SessionID"=p_session_id AND "MessageID" < (SELECT message_id FROM messages WHERE session_id=p_session_id AND message_key=p_message_key LIMIT 1) ORDER BY "MessageID" DESC LIMIT p_num_rows) rows ORDER BY "MessageID" ASC; $$;
CREATE OR REPLACE FUNCTION get_all_epochs_by_session_id_sp(p_session_id integer) RETURNS TABLE ("CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT DISTINCT compaction_epoch_key FROM messages WHERE session_id=p_session_id AND compaction_epoch_key IS NOT NULL ORDER BY compaction_epoch_key; $$;
CREATE OR REPLACE FUNCTION messages_get_count_by_session_id_sp(p_session_id integer) RETURNS TABLE ("Total" integer) LANGUAGE sql AS $$ SELECT COUNT(*)::integer FROM messages WHERE session_id=p_session_id; $$;
CREATE OR REPLACE FUNCTION messages_get_by_session_id_sp(p_session_id integer,p_skip_rows integer,p_num_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "SessionID"=p_session_id ORDER BY "MessageID" DESC OFFSET p_skip_rows LIMIT p_num_rows; $$;
CREATE OR REPLACE FUNCTION messages_get_by_session_idturn_key_sp(p_session_id integer,p_turn_key text) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "SessionID"=p_session_id AND "TurnID"=p_turn_key ORDER BY "SequenceNumber" ASC,"MessageID" ASC; $$;
CREATE OR REPLACE FUNCTION messages_get_by_message_ids_sp(p_message_i_ds_csv text) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT r.* FROM get_message_rows() r JOIN regexp_split_to_table(COALESCE(p_message_i_ds_csv,''), ',') ids(id_text) ON r."MessageID"=NULLIF(trim(ids.id_text),'')::integer ORDER BY r."MessageID" ASC; $$;
CREATE OR REPLACE FUNCTION messages_get_latest_message_key_by_session_id_sp(p_session_id integer) RETURNS TABLE ("MessageKey" text) LANGUAGE sql AS $$ SELECT message_key FROM messages WHERE session_id=p_session_id ORDER BY message_id DESC LIMIT 1; $$;

CREATE OR REPLACE FUNCTION get_messages_by_session_idsp_count_sp(p_session_id integer,p_search text) RETURNS TABLE ("Total" integer) LANGUAGE sql AS $$ SELECT COUNT(*)::integer FROM get_message_rows() WHERE "SessionID"=p_session_id AND ("MessageKey" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Role" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Content" ILIKE '%'||COALESCE(p_search,'')||'%'); $$;
CREATE OR REPLACE FUNCTION get_messages_sp_count_sp(p_search text) RETURNS TABLE ("Total" integer) LANGUAGE sql AS $$ SELECT COUNT(*)::integer FROM get_message_rows() WHERE "MessageKey" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Role" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Content" ILIKE '%'||COALESCE(p_search,'')||'%'; $$;
CREATE OR REPLACE FUNCTION get_messages_by_session_idsp_paging_sp(p_session_id integer,p_search text,p_sort_column text,p_sort_ascending boolean,p_skip_rows integer,p_num_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "SessionID"=p_session_id AND ("MessageKey" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Role" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Content" ILIKE '%'||COALESCE(p_search,'')||'%') ORDER BY CASE WHEN p_sort_column='MessageID' AND p_sort_ascending THEN "MessageID" END ASC, CASE WHEN p_sort_column='MessageID' AND NOT p_sort_ascending THEN "MessageID" END DESC, "MessageID" ASC OFFSET p_skip_rows LIMIT p_num_rows; $$;
CREATE OR REPLACE FUNCTION get_messages_sp_paging_sp(p_search text,p_sort_column text,p_sort_ascending boolean,p_skip_rows integer,p_num_rows integer) RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text) LANGUAGE sql AS $$ SELECT * FROM get_message_rows() WHERE "MessageKey" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Role" ILIKE '%'||COALESCE(p_search,'')||'%' OR "Content" ILIKE '%'||COALESCE(p_search,'')||'%' ORDER BY CASE WHEN p_sort_column='MessageID' AND p_sort_ascending THEN "MessageID" END ASC, CASE WHEN p_sort_column='MessageID' AND NOT p_sort_ascending THEN "MessageID" END DESC, "MessageID" ASC OFFSET p_skip_rows LIMIT p_num_rows; $$;
