CREATE OR REPLACE FUNCTION messages_get_by_session_iddate_range_sp(p_session_id integer,p_start_utc timestamp,p_end_utc timestamp,p_num_rows integer)
RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text)
LANGUAGE sql AS $$
	SELECT *
	FROM get_message_rows()
	WHERE "SessionID" = p_session_id
		AND (p_start_utc IS NULL OR "DateCreated" >= p_start_utc)
		AND (p_end_utc IS NULL OR "DateCreated" <= p_end_utc)
	ORDER BY "MessageID" ASC
	LIMIT p_num_rows;
$$;

CREATE OR REPLACE FUNCTION "Messages_GetBySessionIDDateRangeSp"(p_session_id integer,p_start_utc timestamp,p_end_utc timestamp,p_num_rows integer)
RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text)
LANGUAGE sql AS $$
SELECT * FROM messages_get_by_session_iddate_range_sp(p_session_id,p_start_utc,p_end_utc,p_num_rows);
$$;

CREATE OR REPLACE FUNCTION update_messages_compaction_epoch_by_message_keys_json_sp(p_session_id integer,p_message_keys_json text,p_compaction_epoch integer,p_compaction_epoch_key text)
RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text)
LANGUAGE sql AS $$
	WITH keys AS (
		SELECT DISTINCT trim(value) AS message_key
		FROM json_array_elements_text(p_message_keys_json::json) value
		WHERE length(trim(value)) > 0
	), updated AS (
		UPDATE messages m
		SET compaction_epoch = p_compaction_epoch,
			compaction_epoch_key = p_compaction_epoch_key,
			last_updated = now()
		FROM keys k
		WHERE m.session_id = p_session_id
			AND m.message_key = k.message_key
		RETURNING m.message_id
	)
	SELECT r.*
	FROM get_message_rows() r
	INNER JOIN updated u ON u.message_id = r."MessageID"
	ORDER BY r."SequenceNumber" ASC, r."MessageID" ASC;
$$;

CREATE OR REPLACE FUNCTION "UpdateMessagesCompactionEpochByMessageKeysJsonSp"(p_session_id integer,p_message_keys_json text,p_compaction_epoch integer,p_compaction_epoch_key text)
RETURNS TABLE ("MessageID" integer,"SessionID" integer,"SequenceNumber" integer,"Role" text,"Content" text,"ToolName" text,"ToolArguments" text,"CallID" text,"DateCreated" timestamp,"LastUpdated" timestamp,"Data" text,"IsCompacted" boolean,"CompactionEpoch" integer,"MessageKey" text,"TurnID" text,"CompactionEpochKey" text)
LANGUAGE sql AS $$
SELECT * FROM update_messages_compaction_epoch_by_message_keys_json_sp(p_session_id,p_message_keys_json,p_compaction_epoch,p_compaction_epoch_key);
$$;

CREATE OR REPLACE FUNCTION update_message_compaction_epoch_atomic_sp(p_session_id integer,p_message_key text,p_compaction_epoch integer,p_compaction_epoch_key text)
RETURNS TABLE ("UpdatedRows" integer)
LANGUAGE plpgsql AS $$
DECLARE
	v_message_id integer;
BEGIN
	SELECT message_id INTO v_message_id
	FROM messages
	WHERE session_id = p_session_id
		AND message_key = p_message_key
	ORDER BY message_id ASC
	LIMIT 1;

	IF v_message_id IS NULL THEN
		RETURN QUERY SELECT 0;
		RETURN;
	END IF;

	UPDATE messages
	SET compaction_epoch = p_compaction_epoch,
		compaction_epoch_key = p_compaction_epoch_key,
		last_updated = now()
	WHERE message_id = v_message_id;

	RETURN QUERY SELECT 1;
END;
$$;

CREATE OR REPLACE FUNCTION "UpdateMessageCompactionEpochAtomicSp"(p_session_id integer,p_message_key text,p_compaction_epoch integer,p_compaction_epoch_key text)
RETURNS TABLE ("UpdatedRows" integer)
LANGUAGE sql AS $$
SELECT * FROM update_message_compaction_epoch_atomic_sp(p_session_id,p_message_key,p_compaction_epoch,p_compaction_epoch_key);
$$;

CREATE OR REPLACE FUNCTION update_message_date_created_sp(p_message_id integer,p_date_created timestamp)
RETURNS void LANGUAGE sql AS $$
	UPDATE messages SET date_created = p_date_created WHERE message_id = p_message_id;
$$;

CREATE OR REPLACE FUNCTION "UpdateMessageDateCreatedSp"(p_message_id integer,p_date_created timestamp)
RETURNS void LANGUAGE sql AS $$
SELECT update_message_date_created_sp(p_message_id,p_date_created);
$$;
